<div class="page-head"><h2>Facilities & Benefits</h2><a class="btn btn-light" href="<?=url('/facilities/settings')?>">Facility Settings</a></div>
<div class="grid grid-2"><div class="card"><h3>Add Facility / Benefit</h3><form method="post" action="<?=url('/facilities/store')?>"><?=csrf_field()?><label>Name</label><input name="name" required><label>Category</label><input name="category" placeholder="Insurance, Laptop, Vehicle, Internet"><label>Description</label><textarea name="description"></textarea><label><input type="checkbox" name="is_asset" style="width:auto"> This is a returnable asset</label><button class="btn btn-primary">Save Facility</button></form></div><div class="card"><h3>Eligibility Rule</h3><form method="post" action="<?=url('/facilities/rule/store')?>"><?=csrf_field()?><label>Facility</label><select name="facility_id"><?php foreach($facilities as $f): ?><option value="<?=e($f['id'])?>"><?=e($f['name'])?></option><?php endforeach; ?></select><label>Job Level</label><select name="job_level_id"><?php foreach($levels as $l): ?><option value="<?=e($l['id'])?>"><?=e($l['name'])?></option><?php endforeach; ?></select><label><input type="checkbox" name="is_eligible" checked style="width:auto"> Eligible</label><label>Effective Start</label><input type="date" name="effective_start"><label>Effective End</label><input type="date" name="effective_end"><button class="btn btn-primary">Save Rule</button></form></div></div><br><div class="card"><h3>Eligibility Rules</h3><table class="table"><tr><th>Facility</th><th>Job Level</th><th>Eligible</th><th>Start</th><th>End</th></tr><?php foreach($rules as $r): ?><tr><td><?=e($r['facility_name']??'')?></td><td><?=e($r['job_level_name']??'')?></td><td><?=($r['is_eligible']??0)?'Yes':'No'?></td><td><?=e($r['effective_start']??'')?></td><td><?=e($r['effective_end']??'')?></td></tr><?php endforeach; ?></table></div>
